/*Table structure for table `article` */

DROP TABLE IF EXISTS `article`;

CREATE TABLE `article` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `slug` varchar(1024) NOT NULL,
  `title` varchar(512) NOT NULL,
  `body` text NOT NULL,
  `view` varchar(255) DEFAULT NULL,
  `category_id` int(11) DEFAULT NULL,
  `thumbnail_base_url` varchar(1024) DEFAULT NULL,
  `thumbnail_path` varchar(1024) DEFAULT NULL,
  `status` smallint(6) NOT NULL DEFAULT 0,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `published_at` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_article_author` (`created_by`),
  KEY `fk_article_updater` (`updated_by`),
  KEY `fk_article_category` (`category_id`),
  CONSTRAINT `fk_article_author` FOREIGN KEY (`created_by`) REFERENCES `user_str` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_article_category` FOREIGN KEY (`category_id`) REFERENCES `article_category` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_article_updater` FOREIGN KEY (`updated_by`) REFERENCES `user_str` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `article` */

insert  into `article`(`id`,`slug`,`title`,`body`,`view`,`category_id`,`thumbnail_base_url`,`thumbnail_path`,`status`,`created_by`,`updated_by`,`published_at`,`created_at`,`updated_at`) values (1,'test','test','test',NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL),(2,'class-attendance-help','Class Attendance Help','<p><strong>How Class attendance works on web:</strong><br />Purpose of this option is to provide web based attendance log and note to parent for absents.</p><ol><li>Go to <u>create class attendance</u> and select class to load students, un check/select all absent students, submit attendance and iterate (repeat) same for every class .</li><li>Visit <u>Attendance Summary</u> and review entries added and create more entries if missing for any class.</li><li>Verify attendance and absent count.</li><li>By default Attendance note is diabled for all student classes could see in attendance summary, please ativate from class section for required.</li><li>Once absent count is verified, please proceed and <u>generate attendance</u> note from button at the bottom labeled the attendance summary grid.</li><li>If you generate again on same day, all previous unsent notes will be cancelled and new will be generated for absent students.</li><li>Flash messages will confirm you with numbers of attendance and notes created, read them carefully.</li><li>Every time you generate new notes, all previous unsent notes will be cancelled automatically</li><li>For generated notifications, please check notifications list</li></ol><ul><li>Alternate use, <strong>Attapp </strong>for more accurate and faster way to mark attendance</li></ul>','',1,NULL,NULL,1,1,1,1565877033,1565877900,1565877916),(3,'timetable-help','Timetable help','<p><strong>How timetable works:</strong></p><p>Purpose of this option is to facilitate timetable management.</p><ul><li>To create timetable entries please go to \'Create Timetable\' button.</li><li>First we need to create School timing (hours/periods/class time), find timing in timetable menu section.</li><li>To create timetable entry following need to enter (Teacher, Class, Subject, timing, weekdays)</li><li>To assign teacher please search for teacher already exists (or create) and select.</li><li>To add same entry for multiple days may select weekdays check boxes </li><li>To filter timetable entries, may use filter text and drop down options provided first in every column. </li><li>To print timetable view for any class please click class name.</li><li>To print timetable view for any teacher please click teacher name.</li><li>Class and teacher timetable options are also available in Student Class list and teachers list.</li></ul><p><br></p><p><br></p>','',1,NULL,NULL,1,1,1,1585763782,1585763782,1585808659);

/*Table structure for table `article_attachment` */

DROP TABLE IF EXISTS `article_attachment`;

CREATE TABLE `article_attachment` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `article_id` int(11) NOT NULL,
  `path` varchar(255) NOT NULL,
  `base_url` varchar(255) DEFAULT NULL,
  `type` varchar(255) DEFAULT NULL,
  `size` int(11) DEFAULT NULL,
  `name` varchar(255) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `order` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_article_attachment_article` (`article_id`),
  CONSTRAINT `fk_article_attachment_article` FOREIGN KEY (`article_id`) REFERENCES `article` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `article_attachment` */

/*Table structure for table `article_category` */

DROP TABLE IF EXISTS `article_category`;

CREATE TABLE `article_category` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `slug` varchar(1024) NOT NULL,
  `title` varchar(512) NOT NULL,
  `body` text DEFAULT NULL,
  `parent_id` int(11) DEFAULT NULL,
  `status` smallint(6) NOT NULL DEFAULT 0,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_article_category_section` (`parent_id`),
  CONSTRAINT `fk_article_category_section` FOREIGN KEY (`parent_id`) REFERENCES `article_category` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

