/*Table structure for table `attachment` */

DROP TABLE IF EXISTS `attachment`;

CREATE TABLE `attachment` (
  `id` int(25) NOT NULL AUTO_INCREMENT,
  `path` varchar(1024) NOT NULL,
  `base_url` varchar(255) DEFAULT NULL,
  `type` varchar(255) DEFAULT NULL,
  `size` int(25) DEFAULT NULL,
  `name` varchar(255) DEFAULT NULL,
  `order` int(25) DEFAULT NULL,
  `parent_id` int(25) DEFAULT NULL,
  `status` int(10) DEFAULT 1,
  `updated_at` int(25) DEFAULT NULL,
  `created_at` int(25) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5599 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `attachment` */

/*Table structure for table `batch` */

DROP TABLE IF EXISTS `batch`;

CREATE TABLE `batch` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `school_id` int(11) DEFAULT NULL,
  `title` varchar(25) NOT NULL,
  `details` text DEFAULT NULL,
  `status` int(11) DEFAULT 0,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `schoolid` (`school_id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `batch` */

/*Table structure for table `expense` */

DROP TABLE IF EXISTS `expense`;

CREATE TABLE `expense` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `parent_id` int(11) DEFAULT NULL,
  `title` varchar(50) NOT NULL,
  `category` varchar(50) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `amount` float NOT NULL,
  `payment_date` date DEFAULT NULL,
  `paid_to` varchar(25) DEFAULT NULL,
  `paid_by` varchar(25) DEFAULT NULL,
  `payment_method` varchar(25) DEFAULT NULL,
  `details` text DEFAULT NULL,
  `receipt` varchar(50) DEFAULT NULL,
  `status` int(11) NOT NULL DEFAULT 0,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `expense` */

/*Table structure for table `file_storage_item` */

DROP TABLE IF EXISTS `file_storage_item`;

CREATE TABLE `file_storage_item` (
