/*Table structure for table `i18n_message` */

DROP TABLE IF EXISTS `i18n_message`;

CREATE TABLE `i18n_message` (
  `id` int(11) NOT NULL DEFAULT 0,
  `language` varchar(16) NOT NULL DEFAULT '',
  `translation` text DEFAULT NULL,
  PRIMARY KEY (`id`,`language`),
  CONSTRAINT `fk_i18n_message_source_message` FOREIGN KEY (`id`) REFERENCES `i18n_source_message` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `i18n_message` */

/*Table structure for table `i18n_source_message` */

DROP TABLE IF EXISTS `i18n_source_message`;

CREATE TABLE `i18n_source_message` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `category` varchar(32) DEFAULT NULL,
  `message` text DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `i18n_source_message` */

/*Table structure for table `inventory` */

DROP TABLE IF EXISTS `inventory`;

CREATE TABLE `inventory` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `parent_id` int(11) DEFAULT NULL,
  `item_id` varchar(25) DEFAULT NULL,
  `item_name` varchar(25) NOT NULL,
  `type` varchar(25) DEFAULT NULL,
  `category` varchar(25) DEFAULT NULL,
  `count` varchar(25) NOT NULL,
  `details` text DEFAULT NULL,
  `status` enum('0','1') DEFAULT NULL,
  `last_verified` date DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `inventory` */

/*Table structure for table `key_storage_item` */

DROP TABLE IF EXISTS `key_storage_item`;

CREATE TABLE `key_storage_item` (
  `key` varchar(128) NOT NULL,
  `value` text NOT NULL,
  `comment` text DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`key`),
  UNIQUE KEY `idx_key_storage_item_key` (`key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `key_storage_item` */

insert  into `key_storage_item`(`key`,`value`,`comment`,`updated_at`,`created_at`) values ('backend.layout-boxed','1',NULL,1647185523,NULL),('backend.layout-collapsed-sidebar','1',NULL,1647185692,NULL),('backend.layout-fixed','1',NULL,1647185575,NULL),('backend.theme-skin','skin-green','skin-blue, skin-black, skin-purple, skin-green, skin-red, skin-yellow',1738220115,NULL),('frontend.maintenance','disabled','Set it to \"true\" to turn on maintenance mode',1540029600,NULL);

/*Table structure for table `learning_content` */

DROP TABLE IF EXISTS `learning_content`;

CREATE TABLE `learning_content` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `school_id` int(11) DEFAULT NULL,
  `section_id` int(11) DEFAULT NULL,
  `subject_id` int(11) DEFAULT NULL,
  `teacher_id` int(11) DEFAULT NULL,
  `title` varchar(50) DEFAULT NULL,
  `chapter` varchar(50) DEFAULT NULL,
  `type` varchar(25) DEFAULT NULL,
  `site` varchar(50) DEFAULT NULL,
  `content` text DEFAULT NULL,
  `date` date DEFAULT NULL,
  `status` int(11) DEFAULT NULL,
  `views` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `learning_content` */

/*Table structure for table `notification` */

DROP TABLE IF EXISTS `notification`;

CREATE TABLE `notification` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `school_id` int(11) NOT NULL,
  `parent_id` int(11) DEFAULT NULL,
  `parent_type` varchar(25) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `type` varchar(25) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
