CREATE TABLE `school` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(250) NOT NULL,
  `tagline` varchar(250) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `details` text DEFAULT NULL,
  `address` text DEFAULT NULL,
  `phone` varchar(25) DEFAULT NULL,
  `owner` varchar(250) DEFAULT NULL,
  `principal` int(10) DEFAULT NULL,
  `started_at` date DEFAULT NULL,
  `city` int(11) DEFAULT NULL,
  `country` int(11) DEFAULT NULL,
  `late_payment_fine` float DEFAULT NULL,
  `fine_type` varchar(10) DEFAULT 'month',
  `attendance_ends` varchar(11) DEFAULT NULL,
  `is_deleted` int(2) DEFAULT 0,
  `created_by` int(10) DEFAULT NULL,
  `updated_by` int(10) DEFAULT NULL,
  `created_at` int(10) DEFAULT NULL,
  `updated_at` int(10) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=60 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

