/*Table structure for table `student` */

DROP TABLE IF EXISTS `student`;

CREATE TABLE `student` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `school_id` int(11) DEFAULT NULL,
  `parent_id` int(11) DEFAULT NULL,
  `class_id` int(11) DEFAULT NULL,
  `section_id` int(11) DEFAULT NULL,
  `student_key` varchar(25) DEFAULT NULL,
  `previous_recored_date` date DEFAULT NULL,
  `full_name` varchar(50) NOT NULL,
  `gender` varchar(11) DEFAULT NULL,
  `surname` varchar(25) DEFAULT NULL,
  `father_name` varchar(50) DEFAULT NULL,
  `mother_name` varchar(50) DEFAULT NULL,
  `fee_discount` float DEFAULT NULL,
  `date_of_birth` date DEFAULT NULL,
  `native_place` varchar(50) DEFAULT NULL,
  `admission_date` date DEFAULT NULL,
  `gr_number` varchar(25) DEFAULT NULL,
  `seat_number` int(11) DEFAULT NULL,
  `admit_in_class` varchar(11) DEFAULT NULL,
  `left_in_class` varchar(11) DEFAULT NULL,
  `left_date` date DEFAULT NULL,
  `left_reason` varchar(50) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `locality` varchar(25) DEFAULT NULL,
  `phone` varchar(25) DEFAULT NULL,
  `mobile` varchar(25) DEFAULT NULL,
  `email` varchar(50) DEFAULT NULL,
  `cnic_number` varchar(25) DEFAULT NULL,
  `b_form` varchar(25) DEFAULT NULL,
  `vaccination` varchar(25) DEFAULT NULL,
  `allergies` varchar(50) DEFAULT NULL,
  `religion` varchar(25) DEFAULT NULL,
  `nationality` varchar(25) DEFAULT NULL,
  `previous_school` varchar(50) DEFAULT NULL,
  `seat_number_ninth` varchar(25) DEFAULT NULL,
  `seat_number_tenth` varchar(25) DEFAULT NULL,
  `garde_in_tenth` varchar(11) DEFAULT NULL,
  `certificate_number` varchar(11) DEFAULT NULL,
  `other_details` tinytext DEFAULT NULL,
  `progress` varchar(50) DEFAULT NULL,
  `conduct` varchar(50) DEFAULT NULL,
  `is_private` int(11) DEFAULT NULL,
  `status` int(11) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `schoolid` (`school_id`),
  KEY `parentid` (`parent_id`),
  KEY `section` (`section_id`),
  KEY `classid` (`class_id`),
  CONSTRAINT `FK_student` FOREIGN KEY (`section_id`) REFERENCES `student_class` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `FK_student_class` FOREIGN KEY (`class_id`) REFERENCES `student_class` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `FK_student_parent` FOREIGN KEY (`parent_id`) REFERENCES `user` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `FK_student_school` FOREIGN KEY (`school_id`) REFERENCES `school` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=16038 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `student` */

