DROP TABLE IF EXISTS `student_attendance`;

CREATE TABLE `student_attendance` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `school_id` int(11) DEFAULT NULL,
  `staff_id` int(11) DEFAULT NULL,
  `type` varchar(25) DEFAULT NULL,
  `status` int(11) NOT NULL DEFAULT 0,
  `student_id` int(11) NOT NULL,
  `section_id` int(11) DEFAULT NULL,
  `subject_id` int(11) DEFAULT NULL,
  `date` date NOT NULL,
  `recored_timestamp` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `studentid` (`student_id`),
  KEY `schoolid` (`school_id`),
  CONSTRAINT `FK_student_attendance` FOREIGN KEY (`student_id`) REFERENCES `student` (`id`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=57 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `student_attendance` */

/*Table structure for table `student_class` */

DROP TABLE IF EXISTS `student_class`;

CREATE TABLE `student_class` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `parent_class_id` int(11) NOT NULL DEFAULT 0,
  `title` varchar(25) NOT NULL COMMENT 'Class Name',
  `school_id` int(25) NOT NULL,
  `promote_section_id` int(11) DEFAULT NULL,
  `staff_id` int(25) NOT NULL COMMENT 'Class Incharge',
  `annual_registration_fee` float DEFAULT 0,
  `monthly_tution_fee` float DEFAULT 0,
  `annual_exam_fee` float DEFAULT 0,
  `monthly_test_fee` float DEFAULT 0,
  `terminal_exam_fee` float DEFAULT 0,
  `security_fee` float DEFAULT 0,
  `id_card_fee` float DEFAULT 0,
  `details` text DEFAULT NULL,
  `status` int(11) NOT NULL DEFAULT 0,
  `list_order` int(11) DEFAULT 0,
  `attendance_note` int(11) DEFAULT 0,
  `created_by` int(25) DEFAULT NULL,
  `updated_by` int(25) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id` (`id`),
  KEY `school` (`school_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1021 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `student_class` */

/*Table structure for table `subject` */

DROP TABLE IF EXISTS `subject`;

CREATE TABLE `subject` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(50) NOT NULL,
  `school_id` int(25) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `staff_id` int(50) DEFAULT NULL COMMENT 'Incharge',
  `details` text DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `updated_by` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=189 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `subject` */

