/*Table structure for table `user_profile` */

DROP TABLE IF EXISTS `user_profile`;

CREATE TABLE `user_profile` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `full_name` varchar(255) DEFAULT NULL,
  `firstname` varchar(255) DEFAULT NULL,
  `middlename` varchar(255) DEFAULT NULL,
  `lastname` varchar(255) DEFAULT NULL,
  `surname` varchar(255) DEFAULT NULL,
  `father_name` varchar(50) DEFAULT NULL,
  `mother_name` varchar(50) DEFAULT NULL,
  `email_alternate` varchar(50) DEFAULT NULL,
  `date_of_birth` date DEFAULT NULL,
  `family_key` varchar(25) DEFAULT NULL,
  `CNIC` varchar(15) DEFAULT NULL,
  `nationality` varchar(15) DEFAULT NULL,
  `passport_number` varchar(15) DEFAULT NULL,
  `domicile` varchar(15) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `qualification` varchar(15) DEFAULT NULL,
  `profession` varchar(15) DEFAULT NULL,
  `job_title` varchar(15) DEFAULT NULL,
  `join_date` date DEFAULT NULL,
  `last_date` date DEFAULT NULL,
  `is_working` varchar(15) DEFAULT NULL,
  `disablity` varchar(15) DEFAULT NULL,
  `medical_concern` varchar(255) DEFAULT NULL,
  `social_activity` varchar(255) DEFAULT NULL,
  `languages` varchar(255) DEFAULT NULL,
  `emergency_contact` varchar(255) DEFAULT NULL,
  `phone` varchar(15) DEFAULT NULL,
  `support_school_in` varchar(255) DEFAULT NULL,
  `visit_abroad` varchar(15) DEFAULT NULL,
  `work_at` varchar(15) DEFAULT NULL,
  `cell_number` varchar(255) DEFAULT NULL,
  `information` text DEFAULT NULL,
  `avatar_path` varchar(255) DEFAULT NULL,
  `avatar_base_url` varchar(255) DEFAULT NULL,
  `locale` varchar(32) NOT NULL,
  `gender` smallint(1) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`user_id`),
  CONSTRAINT `fk_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10446 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `user_profile` */

/*Table structure for table `user_progress` */

DROP TABLE IF EXISTS `user_progress`;

CREATE TABLE `user_progress` (
  `id` int(25) NOT NULL AUTO_INCREMENT,
  `created_by_id` int(25) DEFAULT NULL,
  `user_id` int(25) NOT NULL,
  `type` varchar(25) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `status` varchar(10) DEFAULT NULL,
  `create_date` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `user_progress` */

/*Table structure for table `user_str` */

DROP TABLE IF EXISTS `user_str`;

CREATE TABLE `user_str` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(32) DEFAULT NULL,
  `auth_key` varchar(32) NOT NULL,
  `access_token` varchar(40) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `oauth_client` varchar(255) DEFAULT NULL,
  `oauth_client_user_id` varchar(255) DEFAULT NULL,
  `email` varchar(255) NOT NULL,
  `superadmin` smallint(6) DEFAULT 0,
  `status` smallint(6) NOT NULL DEFAULT 2,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  `logged_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

/*Data for the table `user_str` */

/*Table structure for table `user_token` */

DROP TABLE IF EXISTS `user_token`;

CREATE TABLE `user_token` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `type` varchar(255) NOT NULL,
  `token` varchar(40) NOT NULL,
  `expire_at` int(11) DEFAULT NULL,
  `created_at` int(11) DEFAULT NULL,
  `updated_at` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

/*Data for the table `user_token` */

/*Table structure for table `user_visit_log` */

DROP TABLE IF EXISTS `user_visit_log`;

CREATE TABLE `user_visit_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `token` varchar(255) NOT NULL,
  `ip` varchar(15) NOT NULL,
  `language` char(2) NOT NULL,
  `user_agent` varchar(255) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `visit_time` int(11) NOT NULL,
  `browser` varchar(30) DEFAULT NULL,
  `os` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`id`),
